/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering, recipient validation, and delivery
 * with retry support. In non-production environments, emails are
 * captured in memory for testing/inspection rather than sent via SMTP.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
}

export interface EmailConfig {
  /** SMTP host for sending emails. */
  smtpHost: string;
  /** SMTP port. */
  smtpPort: number;
  /** Sender address for outbound emails. */
  fromAddress: string;
  /** Number of retry attempts on transient failures. */
  maxRetries: number;
  /** Base delay in ms between retries (doubled each attempt). */
  retryDelayMs: number;
}

const DEFAULT_EMAIL_CONFIG: EmailConfig = {
  smtpHost: 'localhost',
  smtpPort: 587,
  fromAddress: 'noreply@taskflow.io',
  maxRetries: 3,
  retryDelayMs: 200,
};

/** Email templates keyed by notification type. */
interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  html: (payload: NotificationPayload) => string;
}

const EMAIL_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  'order:confirmation': {
    subject: (p) => p.subject,
    html: (p) => renderHtmlWrapper(
      'Order Confirmation',
      `<h2>Thank you for your order!</h2>
      <p>${escapeHtml(p.body)}</p>
      ${p.metadata?.orderId ? `<p><strong>Order ID:</strong> ${escapeHtml(String(p.metadata.orderId))}</p>` : ''}
      <p>We'll notify you when your order status changes.</p>`,
    ),
  },
  'order:status-update': {
    subject: (p) => p.subject,
    html: (p) => renderHtmlWrapper(
      'Order Status Update',
      `<h2>Your order has been updated</h2>
      <p>${escapeHtml(p.body)}</p>
      ${p.metadata?.newStatus ? `<p><strong>Current Status:</strong> ${escapeHtml(String(p.metadata.newStatus))}</p>` : ''}`,
    ),
  },
  'user:welcome': {
    subject: (p) => p.subject,
    html: (p) => renderHtmlWrapper(
      'Welcome to TaskFlow!',
      `<h2>Welcome aboard!</h2>
      <p>${escapeHtml(p.body)}</p>
      <p>Get started by creating your first order.</p>`,
    ),
  },
  'user:profile-updated': {
    subject: (p) => p.subject,
    html: (p) => renderHtmlWrapper(
      'Profile Updated',
      `<h2>Your profile has been updated</h2>
      <p>${escapeHtml(p.body)}</p>`,
    ),
  },
};

/**
 * Escape HTML special characters to prevent XSS in email templates.
 */
export function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Wrap email content in a basic HTML email layout.
 */
function renderHtmlWrapper(title: string, innerHtml: string): string {
  return `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><title>${escapeHtml(title)}</title></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">
  <div style="border-bottom: 2px solid #4a90d9; padding-bottom: 10px; margin-bottom: 20px;">
    <h1 style="color: #4a90d9; margin: 0;">TaskFlow</h1>
  </div>
  ${innerHtml}
  <div style="border-top: 1px solid #ddd; margin-top: 30px; padding-top: 10px; color: #888; font-size: 12px;">
    <p>This is an automated message from TaskFlow. Please do not reply directly.</p>
  </div>
</body>
</html>`;
}

/** Simple email address validation. */
export function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * Resolve the display-friendly recipient from a payload.
 * If the recipient is an email, returns it directly.
 * If metadata contains a resolved email, uses that instead.
 */
export function resolveRecipient(payload: NotificationPayload): string | null {
  // Check metadata for an explicit email override
  if (payload.metadata?.email && typeof payload.metadata.email === 'string') {
    const metaEmail = payload.metadata.email;
    if (isValidEmail(metaEmail)) {
      return metaEmail;
    }
  }

  // Use the recipient field directly if it's a valid email
  if (isValidEmail(payload.recipient)) {
    return payload.recipient;
  }

  return null;
}

/**
 * Render an email from a notification payload using the template
 * for the payload's notification type.
 */
export function renderEmail(payload: NotificationPayload): { subject: string; html: string } {
  const template = EMAIL_TEMPLATES[payload.type];
  return {
    subject: template.subject(payload),
    html: template.html(payload),
  };
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private config: EmailConfig;

  /** Optional hook for tests to simulate SMTP failures. */
  private smtpSendFn: ((email: SentEmail) => Promise<boolean>) | null = null;

  constructor(config?: Partial<EmailConfig>) {
    this.config = { ...DEFAULT_EMAIL_CONFIG, ...config };
  }

  /**
   * Override the internal SMTP send function (for testing).
   * When set, this function is called instead of the default
   * in-memory capture, allowing tests to simulate failures.
   */
  setSmtpSendFn(fn: (email: SentEmail) => Promise<boolean>): void {
    this.smtpSendFn = fn;
  }

  /**
   * Send an email notification.
   * Validates recipient, renders template, and delivers with retry.
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    const recipient = resolveRecipient(payload);
    if (!recipient) {
      this.logger.error(`Invalid or unresolvable email recipient: ${payload.recipient}`);
      return false;
    }

    const { subject, html } = renderEmail(payload);

    const email: SentEmail = {
      to: recipient,
      subject,
      body: payload.body,
      htmlBody: html,
      sentAt: new Date(),
    };

    this.logger.info(`Sending email to ${recipient}: ${subject}`);

    const delivered = await this.deliverWithRetry(email);

    if (delivered) {
      this.sentEmails.push(email);
      this.logger.info(`Email delivered to ${recipient}`);
    } else {
      this.logger.error(`Email delivery failed to ${recipient} after ${this.config.maxRetries} retries`);
    }

    return delivered;
  }

  /**
   * Attempt delivery with exponential-backoff retries.
   */
  private async deliverWithRetry(email: SentEmail): Promise<boolean> {
    let delay = this.config.retryDelayMs;

    for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
      try {
        const success = await this.smtpSend(email);
        if (success) {
          return true;
        }
      } catch (err) {
        this.logger.warn(
          `SMTP send attempt ${attempt + 1} failed: ${err instanceof Error ? err.message : String(err)}`,
        );
      }

      if (attempt < this.config.maxRetries) {
        await this.sleep(delay);
        delay *= 2;
      }
    }

    return false;
  }

  /**
   * Internal SMTP send. Uses the test hook if set, otherwise
   * captures the email in memory (simulating a successful send).
   */
  private async smtpSend(email: SentEmail): Promise<boolean> {
    if (this.smtpSendFn) {
      return this.smtpSendFn(email);
    }
    // Default: in-memory capture (for dev/test)
    return true;
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the current adapter configuration.
   */
  getConfig(): EmailConfig {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  escapeHtml,
  isValidEmail,
  resolveRecipient,
  renderEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter();
  });

  describe('send', () => {
    it('should send email for a valid recipient', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.body).toContain('Widget x2');
      expect(sent[0]?.htmlBody).toContain('Thank you for your order');
    });

    it('should reject invalid email recipients', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'not-an-email',
        subject: 'Test',
        body: 'Test body',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should use metadata email override when recipient is not an email', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: 'user-123',
        subject: 'Order Update: order-1',
        body: 'Status changed from pending to confirmed.',
        metadata: { email: 'bob@example.com' },
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(adapter.getSentEmails()[0]?.to).toBe('bob@example.com');
    });

    it('should render HTML template for order confirmation', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        metadata: { orderId: 'order-1' },
      };

      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.htmlBody).toContain('Order Confirmation');
      expect(sent[0]?.htmlBody).toContain('order-1');
      expect(sent[0]?.htmlBody).toContain('TaskFlow');
      expect(sent[0]?.htmlBody).toContain('<!DOCTYPE html>');
    });

    it('should render HTML template for order status update', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: 'alice@example.com',
        subject: 'Order Update: order-1',
        body: 'Status changed.',
        metadata: { newStatus: 'shipped' },
      };

      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.htmlBody).toContain('Order Status Update');
      expect(sent[0]?.htmlBody).toContain('shipped');
    });

    it('should render HTML template for user welcome', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'newuser@example.com',
        subject: 'Welcome to TaskFlow!',
        body: 'Welcome, New User!',
      };

      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.htmlBody).toContain('Welcome aboard');
      expect(sent[0]?.htmlBody).toContain('Get started');
    });

    it('should render HTML template for profile update', async () => {
      const payload: NotificationPayload = {
        type: 'user:profile-updated',
        recipient: 'alice@example.com',
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
      };

      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.htmlBody).toContain('Profile Updated');
    });
  });

  describe('retry behavior', () => {
    it('should retry on transient SMTP failure and succeed', async () => {
      adapter = new EmailNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setSmtpSendFn(async () => {
        attempts++;
        if (attempts < 2) {
          throw new Error('Connection refused');
        }
        return true;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(2);
      expect(adapter.getSentEmails()).toHaveLength(1);
    });

    it('should fail after exhausting all retries', async () => {
      adapter = new EmailNotificationAdapter({ maxRetries: 1, retryDelayMs: 1 });

      adapter.setSmtpSendFn(async () => {
        throw new Error('SMTP server down');
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should retry when send returns false', async () => {
      adapter = new EmailNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setSmtpSendFn(async () => {
        attempts++;
        return attempts >= 3;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(3);
    });
  });

  describe('configuration', () => {
    it('should use default config', () => {
      const config = adapter.getConfig();
      expect(config.smtpHost).toBe('localhost');
      expect(config.smtpPort).toBe(587);
      expect(config.fromAddress).toBe('noreply@taskflow.io');
      expect(config.maxRetries).toBe(3);
    });

    it('should accept custom config', () => {
      const custom = new EmailNotificationAdapter({
        smtpHost: 'smtp.example.com',
        smtpPort: 465,
        fromAddress: 'support@example.com',
      });
      const config = custom.getConfig();
      expect(config.smtpHost).toBe('smtp.example.com');
      expect(config.smtpPort).toBe(465);
      expect(config.fromAddress).toBe('support@example.com');
      expect(config.maxRetries).toBe(3); // still default
    });
  });

  describe('clearSentEmails', () => {
    it('should clear sent email history', async () => {
      await adapter.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
      });

      expect(adapter.getSentEmails()).toHaveLength(1);
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

describe('escapeHtml', () => {
  it('should escape HTML special characters', () => {
    expect(escapeHtml('<script>alert("xss")</script>')).toBe(
      '&lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;',
    );
  });

  it('should escape ampersands', () => {
    expect(escapeHtml('foo & bar')).toBe('foo &amp; bar');
  });

  it('should handle plain text unchanged', () => {
    expect(escapeHtml('Hello World')).toBe('Hello World');
  });
});

describe('isValidEmail', () => {
  it('should accept valid emails', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
    expect(isValidEmail('user+tag@sub.domain.com')).toBe(true);
  });

  it('should reject invalid emails', () => {
    expect(isValidEmail('not-an-email')).toBe(false);
    expect(isValidEmail('@missing.local')).toBe(false);
    expect(isValidEmail('missing@')).toBe(false);
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('has spaces@example.com')).toBe(false);
  });
});

describe('resolveRecipient', () => {
  it('should return recipient if it is a valid email', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test',
    };
    expect(resolveRecipient(payload)).toBe('alice@example.com');
  });

  it('should prefer metadata email over non-email recipient', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'user-123',
      subject: 'Test',
      body: 'Test',
      metadata: { email: 'resolved@example.com' },
    };
    expect(resolveRecipient(payload)).toBe('resolved@example.com');
  });

  it('should return null when no valid email can be resolved', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'user-123',
      subject: 'Test',
      body: 'Test',
    };
    expect(resolveRecipient(payload)).toBeNull();
  });

  it('should ignore invalid metadata email and fall back to recipient', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test',
      metadata: { email: 'not-valid' },
    };
    expect(resolveRecipient(payload)).toBe('alice@example.com');
  });
});

describe('renderEmail', () => {
  it('should render order confirmation template', () => {
    const result = renderEmail({
      type: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Items: Widget x2',
    });

    expect(result.subject).toBe('Order Confirmation: order-1');
    expect(result.html).toContain('Thank you for your order');
    expect(result.html).toContain('Items: Widget x2');
  });

  it('should include metadata in template when available', () => {
    const result = renderEmail({
      type: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test',
      metadata: { orderId: 'ORD-999' },
    });

    expect(result.html).toContain('ORD-999');
  });

  it('should escape HTML in body content', () => {
    const result = renderEmail({
      type: 'order:confirmation',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: '<script>alert("xss")</script>',
    });

    expect(result.html).not.toContain('<script>');
    expect(result.html).toContain('&lt;script&gt;');
  });
});

